function maxOperations(s) {
    let count = 0;
    while (s.length > 0) {
        for (let i = Math.floor(s.length / 2); i > 0; i--) {
            if (s.slice(0, i) === s.slice(i, 2 * i)) {
                s = s.slice(i);
                count++;
                break;
            } else if (i === 1) {
                s = s.slice(1);
                count++;
            }
        }
    }
    return count;
}
